	--color-card-bg: #ffffff;
	--color-card-border: #cfd9ec;
	--color-card-shadow: rgba(20, 56, 128, 0.14);
	--color-link: #365a97;
	--color-header: #173974;
	--color-label: #1f3f77;
	--color-input-border: #c9d6f0;
	--color-input-text: #2f3d56;
