.el-card {
    box-shadow: none !important;
    border: none !important;
    background: transparent !important;
}

.el-card__body {
    padding: 10px !important;
}

/* =========================================================
   2. FIX TEXT WRAPPING (The "Text" Fix)
   ========================================================= */

/* The wrapper allows scrolling if the table is WIDER than the screen */
.text-content, .description {
    overflow-x: auto !important;
    width: 100% !important;
}

table {
    width: 100% !important;
    min-width: 1200px; /* Force table to be at least this wide */
    border-collapse: collapse;
    background-color: #fff;
    margin-bottom: 20px;
}

/* THE IMPORTANT PART: Prevent wrapping */
th, td {
    white-space: nowrap !important; /* <--- THIS STOPS TEXT WRAPPING */
    padding: 12px 15px !important;
    border: 1px solid #ddd !important;
    text-align: left;
    font-size: 13px;
}

