=<!DOCTYPE html>
<html>
<head>
<style>
  body {
    font-family: Arial, sans-serif;
    font-size: 14px;
    color: #333333;
    line-height: 1.6;
  }
  .header {
    text-align: center;
    border-bottom: 3px solid #1a3c6e;
    padding-bottom: 15px;
    margin-bottom: 20px;
