    color: #c0392b;
    margin: 5px 0;
  }
  .ref-section {
    display: flex;
    justify-content: space-between;
    margin-bottom: 15px;
  }
  .student-info {
    background-color: #f5f7fa;
    padding: 12px 18px;
    border-left: 4px solid #1a3c6e;
    margin-bottom: 20px;
  }
  .student-info p {
    margin: 4px 0;
  }
  .fee-table {
    width: 100%;
    border-collapse: collapse;
    margin: 15px 0;
  }
  .fee-table th {
    background-color: #1a3c6e;
    color: #ffffff;
    padding: 10px;
    text-align: left;
  }
  .fee-table td {
    border: 1px solid #dddddd;
    padding: 8px 10px;
  }
  .fee-table tr:nth-child(even) {
    background-color: #f2f2f2;
  }
  .fee-table .total-row {
    background-color: #fdecea !important;
    font-weight: bold;
    color: #c0392b;
  }
  .warning-box {
    background-color: #fdecea;
    border: 1px solid #c0392b;
    border-left: 5px solid #c0392b;
    padding: 15px;
    margin: 20px 0;
  }
  .warning-box h4 {
    color: #c0392b;
    margin-top: 0;
  }
  .payment-box {
    background-color: #eaf7ea;
    border: 1px solid #27ae60;
    border-left: 5px solid #27ae60;
    padding: 15px;
    margin: 20px 0;
  }
  .payment-box h4 {
    color: #27ae60;
    margin-top: 0;
  }
  .footer {
    border-top: 2px solid #1a3c6e;
    padding-top: 15px;
    margin-top: 30px;
    font-size: 12px;
    color: #777777;
    text-align: center;
  }
  .deadline {
    color: #c0392b;
    font-weight: bold;
    font-size: 16px;
  }
</style>
</head>
<body>

<!-- ====== HEADER ====== -->
<div class="header">
    <h2>{{ $('Logged School').item.json.school_name.toUpperCase() }}</h2>
  <p>{{ $('Logged School').item.json.campus }}, {{ $('Logged School').item.json.city }}, {{ $('Logged School').item.json.country }} - EMIS # {{ $('Logged School').item.json.emis_code  }}<br>
  Phone: {{ $('Logged School').item.json.contact_number1 }} | Email: {{ $('Logged School').item.json.email }}</p>
  <h3>NOTICE — OUTSTANDING FEE PAYMENT</h3>
</div>

<!-- ====== REFERENCE & DATE ====== -->
<table width="100%" style="margin-bottom:15px;">
  <tr>

    <td style="text-align:right;"><strong>Date:</strong> {{ $now.format('dd MMMM yyyy') }}</td>
  </tr>
</table>

<!-- ====== STUDENT INFO ====== -->
<div class="student-info">
  <p><strong>Student Name:</strong> {{ $('Loop Over Items3').item.json.student_name }}</p>
  <br>
  <p><strong>Session:</strong> {{ $json.session_name }}</p>
  <p><strong>Class / Course:</strong> {{ $json.student_class }} — {{ $json.student_course }}</p>

  <p><strong>Roll No. / Reg. No.:</strong> {{ $json.student_reg }}</p>
  <p><strong>Parent / Guardian Name:</strong> {{ $json.guardian_name }}</p>
</div>

<!-- ====== SUBJECT LINE ====== -->
<p><strong>Subject: Pending Fee Balance — Final Notice</strong></p>

<!-- ====== BODY ====== -->
<p>Dear <strong> {{ $json.guardian_name }}</strong>,</p>

<p>Greetings from <strong>{{ $('Logged School').item.json.school_name }}</strong>.</p>

<p>This is to bring to your kind attention that as per our records, the fee account
of <strong> {{ $('Loop Over Items3').item.json.student_name }} </strong> {{ $json.relation_w_guardian }} </strong> {{ $json.guardian_name }}</strong>, reflects an outstanding balance of <b> {{ $json.bal_tilldate }} </b>.

<!-- ====== WARNING BOX ====== -->
<div class="warning-box">
  <h4>IMPORTANT — CONSEQUENCES OF NON-PAYMENT</h4>
  <p>You are hereby requested to clear all pending dues on or before
  <span class="deadline">{{ $now.plus(10,"days").format('dd MMMM yyyy') }}</span>.
  <br>Failure to comply shall result in the following actions
  <strong>without any further intimation</strong>:</p>
  <ol>
    <li>The <strong>name of your ward shall be struck off</strong> from the institution rolls.</li>
    <li>The student will <strong>not be permitted to attend classes</strong> or appear in any examination.</li>
    <li>Access to all institutional facilities, including library, laboratories, and online portals, shall be <strong>revoked immediately</strong>.</li>
    <li>Any pending result or certificate shall be <strong>withheld</strong> until full settlement of dues.</li>
  </ol>
</div>

<!-- ====== CLOSING ====== -->
<p>Should you have any queries, you are welcome to contact the undersigned or visit the Accounts Office
<strong>before the deadline</strong> to discuss the matter.</p>

<p>We value your ward's association with our institution and hope for your
prompt cooperation in resolving this matter amicably.</p>

<p>Thanking you.</p>

<br>
<p>
  Yours sincerely,<br><br>
  <strong>Akbar Mehmood</strong><br>
  Principal<br>
  {{ $('Logged School').item.json.school_name }}<br>
  Contact: {{ $('Logged School').item.json.contact_number1 }}<br>
  Email: {{ $('Logged School').item.json.email }}
</p>

<!-- ====== FOOTER ====== -->
<div class="footer">
  <p>This is a system-generated notice. For any discrepancy in the fee amount,
  please contact the Accounts Office within 3 working days of receiving this notice.</p>
  <p><em>© {{ $now.format('yyyy') }} {{ $('Logged School').item.json.school_name }}. All Rights Reserved.</em></p>
</div>

</body>
</html>

options.customCss:
:root {
  /* --- KEEPING YOUR ORIGINAL VARIABLES --- */
  --font-family: 'Open Sans', sans-serif;
  --color-background: #fbfcfe;
  --color-card-bg: #ffffff;
  --color-submit-btn-bg: #ff6d5a;
  --color-submit-btn-text: #ffffff;

  /* --- ADJUSTED VARIABLES FOR TABLE --- */
  --font-size-body: 13px; /* Slightly smaller font helps fit more columns */
}

/* =========================================================
   1. FORCE FULL SCREEN WIDTH (The "Container" Fix)
   ========================================================= */

/* This overrides n8n's default setting that centers the form in a tiny box */
.n8n-form-container, 
.el-row, 
.el-col, 
.el-card, 
form {
    max-width: 98vw !important; /* Use 98% of the Viewport Width */
    width: 98vw !important;
    margin: 0 auto !important;
    left: 0 !important;
    right: 0 !important;
}

/* Remove the shadow/border of the card to look like a full webpage */
.el-card {
    box-shadow: none !important;
    border: none !important;
    background: transparent !important;
}

.el-card__body {
    padding: 10px !important;
}

/* =========================================================
   2. FIX TEXT WRAPPING (The "Text" Fix)
   ========================================================= */

/* The wrapper allows scrolling if the table is WIDER than the screen */
.text-content, .description {
    overflow-x: auto !important;
    width: 100% !important;
}

table {
    width: 100% !important;
    min-width: 1200px; /* Force table to be at least this wide */
    border-collapse: collapse;
    background-color: #fff;
    margin-bottom: 20px;
}

/* THE IMPORTANT PART: Prevent wrapping */
th, td {
    white-space: nowrap !important; /* <--- THIS STOPS TEXT WRAPPING */
    padding: 12px 15px !important;
    border: 1px solid #ddd !important;
    text-align: left;
    font-size: 13px;
}

/* =========================================================
   3. VISUAL STYLING (The "Pretty" Fix)
   ========================================================= */

/* Header Styling */
thead tr {
    background-color: #009879 !important;
    color: #ffffff !important;
}

th {
    font-weight: bold;
    text-transform: uppercase;
}

/* Zebra Striping */
tbody tr:nth-of-type(even) {
    background-color: #f3f3f3 !important;
}

/* Hover Effect */
tbody tr:hover {
    background-color: #e8f4f2 !important;
    cursor: default;
}

/* Center the Submit button at the bottom */
.el-form-item__content {
    display: flex;
    justify-content: center;
}

