const items = $input.all();

const monthRegex = /^[A-Za-z]{3} \d{2}$/;

// Month mapping
const monthMap = {
  Jan: 0, Feb: 1, Mar: 2, Apr: 3,
  May: 4, Jun: 5, Jul: 6, Aug: 7,
  Sep: 8, Oct: 9, Nov: 10, Dec: 11
};

let output = [];

for (const entry of items) {

  const item = entry.json;

  let result = {
    student_reg: item["Student reg"],
    Name: item.Name,
    Session: item.Session,
    Class: item.Class,
    Course: item.Course,
    Status: item.Status,
    "Guardian Name": item["Guardian Name"],
    student_monthly_fee: cleanNumber(item["Monthly Fee"]),
  };

  // ✅ Extract month columns properly
  const monthKeys = Object.keys(item)
    .filter(key => monthRegex.test(key))
    .map(key => {
      const [mon, yr] = key.split(" ");
      return {
        original: key,
        year: 2000 + Number(yr),
        month: monthMap[mon]
      };
    })
    .sort((a, b) => {
      if (a.year !== b.year) return a.year - b.year;
      return a.month - b.month;
    });

  // ✅ Map strictly in sorted order
  monthKeys.forEach((obj, index) => {
    const mKey = `m${String(index + 1).padStart(2, "0")}`;
    result[mKey] = cleanNumber(item[obj.original]);
  });

  output.push({ json: result });
}

function cleanNumber(value) {
  if (!value) return 0;
  return Number(String(value).replace(/,/g, ""));
}

return output;

