parameters.jsCode:
const items = $input.all();

const fmt = (val) => {
  if (val === '-' || val === null || val === undefined || val === '') return '-';
  const num = Number(val);
  if (isNaN(num)) return '-';
  return num.toLocaleString('en-US', { minimumFractionDigits: 0 });
};

// ── FIRST PASS: Build all rows ──
const rows = items.map(item => {
  const d = item.json;
  const fromDate = new Date(d.session_from);

  const monthLabel = (offset) => {
    const dt = new Date(fromDate);
    dt.setMonth(dt.getMonth() + offset);
    return dt.toLocaleString('en-US', { month: 'short', year: '2-digit' });
  };

  const mv = (i) => {
    const pad = String(i).padStart(2, '0');
    const keys = [`m${pad}`, `M${pad}`, `m${i}`, `M${i}`];
    for (const key of keys) {
      if (key in d && d[key] !== undefined && d[key] !== null && d[key] !== '') {
        if (d[key] === '-') return '-';
        const num = Number(d[key]);
        if (isNaN(num)) return '-';
        return num.toLocaleString('en-US', { minimumFractionDigits: 0 });
      }
    }
    return '-';
  };

  const row = {
    'Student reg'      : d.student_reg    || '-',
    'Session'          : d.session_name   || '-',
    'Class'            : d.student_class  || '-',
    'Course'           : d.student_course || '-',
    'Name'             : d.student_name   || '-',
    'Guardian Name'    : d.guardian_name   || '-',
    'Status'           : d.student_status || '-',
    'Monthly Fee'      : fmt(d.monthly_fee),
    'Payable Tilldate' : fmt(d.due_tilldate),
    'Paid Tilldate'    : fmt(d.total_paid),
    'Balance'          : fmt(d.bal_tilldate),
  };

  for (let i = 0; i < 24; i++) {
    row[monthLabel(i)] = mv(i + 1);
  }

  return row;
});

// ── SECOND PASS: Collect ALL unique column names ──
const allKeys = [];
const keySet = new Set();
rows.forEach(row => {
  Object.keys(row).forEach(k => {
    if (!keySet.has(k)) {
      keySet.add(k);
      allKeys.push(k);
    }
  });
});

// ── THIRD PASS: Fill missing columns with '-' ──
const results = rows.map(row => {
  const filled = {};
  allKeys.forEach(key => {
    filled[key] = (row[key] !== undefined && row[key] !== null) ? row[key] : '-';
  });
  return { json: filled };
});

return results;

