:root {
	/* Typography */
	--font-family: "Segoe UI", Tahoma, Arial, sans-serif;
	--font-weight-normal: 400;
	--font-weight-bold: 600;
	--font-size-body: 14px;
	--font-size-label: 14px;
	--font-size-test-notice: 12px;
	--font-size-input: 15px;
	--font-size-header: 24px;
	--font-size-paragraph: 14px;
	--font-size-link: 13px;
	--font-size-error: 12px;
	--font-size-html-h1: 30px;
	--font-size-html-h2: 22px;
	--font-size-html-h3: 18px;
	--font-size-html-h4: 16px;
	--font-size-html-h5: 14px;
	--font-size-html-h6: 12px;
	--font-size-subheader: 15px;

	/* Colors */
	--color-background: #edf3ff;
	--color-test-notice-text: #7a5b12;
	--color-test-notice-bg: #fff8e6;
	--color-test-notice-border: #eed9a6;
	--color-card-bg: #ffffff;
	--color-card-border: #d5deef;
	--color-card-shadow: rgba(18, 52, 110, 0.14);
	--color-link: #1f4fa3;
	--color-header: #163b7a;
	--color-label: #204379;
	--color-input-border: #c9d6ef;
	--color-input-text: #24324a;
	--color-focus-border: #2d63c8;
	--color-submit-btn-bg: #1f4fa3;
	--color-submit-btn-text: #ffffff;
	--color-error: #d72638;
	--color-required: #1f4fa3;
	--color-clear-button-bg: #5d6d8b;
	--color-html-text: #33415c;
	--color-html-link: #1f4fa3;
	--color-header-subtext: #4d6185;

	/* Shape */
	--border-radius-card: 14px;
	--border-radius-input: 10px;
	--border-radius-clear-btn: 50%;
	--card-border-radius: 14px;

	/* Spacing */
	--padding-container-top: 28px;
	--padding-card: 28px;
	--padding-test-notice-vertical: 12px;
	--padding-test-notice-horizontal: 20px;
	--margin-bottom-card: 16px;
	--padding-form-input: 12px;
	--card-padding: 28px;
	--card-margin-bottom: 16px;

	/* Dimensions */
	--container-width: 460px;
	--submit-btn-height: 50px;
	--checkbox-size: 18px;

	/* Effects */
	--box-shadow-card: 0 14px 32px 0 var(--color-card-shadow);
	--opacity-placeholder: 0.58;
}

/* Background (no external image) */
html, body {
	background:
		radial-gradient(circle at 20% 20%, #f7faff 0%, #edf3ff 45%, #e7efff 100%) !important;
}

/* Improve readability and visual polish */
input, select, textarea {
	border-radius: var(--border-radius-input);
	font-size: var(--font-size-input);
	transition: border-color 0.2s ease, box-shadow 0.2s ease, background-color 0.2s ease;
}

input:focus, select:focus, textarea:focus {
	outline: none;
	border-color: var(--color-focus-border) !important;
	box-shadow: 0 0 0 3px rgba(45, 99, 200, 0.16);
	background-color: #ffffff;
}

label {
	letter-spacing: 0.1px;
}

/* Animated button color theme */
button[type="submit"] {
	background: linear-gradient(120deg, #1f4fa3, #2d63c8, #3b82f6, #2d63c8, #1f4fa3) !important;
	background-size: 280% 280%;
	color: var(--color-submit-btn-text) !important;
	border: none !important;
	border-radius: 12px;
	font-weight: 700;
	letter-spacing: 0.2px;
	transition: transform 0.18s ease, filter 0.18s ease, box-shadow 0.2s ease;
	animation: schoolBtnShift 6s ease infinite;
	box-shadow: 0 8px 18px rgba(31, 79, 163, 0.28);
}

button[type="submit"]:hover {
	transform: translateY(-1px);
	filter: brightness(1.05);
	box-shadow: 0 10px 22px rgba(31, 79, 163, 0.35);
}

button[type="submit"]:active {
	transform: translateY(0);
	filter: brightness(0.98);
}

@keyframes schoolBtnShift {
	0% { background-position: 0% 50%; }
	50% { background-position: 100% 50%; }
	100% { background-position: 0% 50%; }
}
